const users = $input.item.json;
const userArray = Array.isArray(users) ? users : users.data || users.users || [];
return userArray.map(user => ({ json: user }));

const d = $input.item.json;
const portfolio = d.portfolio || d;
const totalValue = Number(portfolio.totalValue || 0).toFixed(2);
const dailyPnl = Number(portfolio.dailyPnl || 0).toFixed(2);
const dailyPnlPct = Number(portfolio.dailyPnlPercent || 0).toFixed(2);
const totalReturn = Number(portfolio.totalReturn || 0).toFixed(2);
const sharpe = Number(portfolio.sharpeRatio || 0).toFixed(3);
const maxDrawdown = Number(portfolio.maxDrawdown || 0).toFixed(2);
const pnlColor = dailyPnl >= 0 ? '#00C805' : '#ff4444';
const pnlEmoji = dailyPnl >= 0 ? '📈' : '📉';

return [{
  json: {
    ...d,
    emailSubject: `[Alpha Terminal] ${pnlEmoji} Daily Digest — ${new Date().toLocaleDateString()}`,
    emailBody: `
<div style="font-family:Inter,sans-serif;background:#0a0a0a;color:#fff;padding:24px;max-width:600px">
  <h1 style="color:#00C805;font-family:'Playfair Display',serif">Alpha Terminal</h1>
  <h2 style="color:#ccc">Daily Portfolio Digest — ${new Date().toLocaleDateString()}</h2>
  <div style="background:#111;border:1px solid #1e1e1e;border-radius:8px;padding:16px;margin:16px 0">
    <div style="font-size:32px;font-family:serif;color:#fff">$${totalValue}</div>
    <div style="color:${pnlColor};font-size:18px">${pnlEmoji} $${dailyPnl} (${dailyPnlPct}%) today</div>
  </div>
  <table style="width:100%;border-collapse:collapse">
    <tr><td style="padding:8px;color:#888">Total Return</td><td style="color:${totalReturn >= 0 ? '#00C805' : '#ff4444'}">$${totalReturn}</td></tr>
    <tr><td style="padding:8px;color:#888">Sharpe Ratio</td><td style="color:#fff">${sharpe}</td></tr>
    <tr><td style="padding:8px;color:#888">Max Drawdown</td><td style="color:#ff4444">-$${Math.abs(maxDrawdown)}</td></tr>
    <tr><td style="padding:8px;color:#888">Positions</td><td style="color:#fff">${portfolio.positionCount || 'N/A'}</td></tr>
  </table>
  <p style="color:#555;font-size:11px;margin-top:24px">Alpha Terminal · Paper Trading Simulator</p>
</div>`,
    toEmail: d.email
  }
}];
